import anthropic

client = anthropic.Anthropic()

JUDGE_PROMPT = """
You are an impartial evaluator. Rate the following AI response on a scale of 1-10
for accuracy, helpfulness, and clarity. Provide a brief justification.

User question: {question}
AI response: {response}

Respond with JSON: {{"score": <1-10>, "justification": "..."}}
"""

def llm_judge(question: str, response: str) -> dict:
    result = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        messages=[{
            "role": "user",
            "content": JUDGE_PROMPT.format(question=question, response=response)
        }]
    )
    import json
    return json.loads(result.content[0].text)

verdict = llm_judge(
    question="What is a transformer model?",
    response="A transformer is a neural network architecture..."
)
print(verdict)  # {"score": 8, "justification": "Accurate and clear..."}

import openai, math
from collections import Counter

client = openai.OpenAI()

def sample_answer(question: str, model: str, n: int = 3) -> tuple[str, float]:
    answers = []
    for _ in range(n):
        r = client.chat.completions.create(
            model=model,
            messages=[{"role": "user", "content": question}],
            temperature=0.5, max_tokens=128
        )
        answers.append(r.choices[0].message.content.strip())
    counts = Counter(answers)
    top, count = counts.most_common(1)[0]
    return top, count / n  # (answer, confidence)

def cascade(question: str, threshold: float = 0.7) -> dict:
    # Tier 1 — cheap model
    answer, conf = sample_answer(question, "gpt-4o-mini", n=3)
    if conf >= threshold:
        return {"answer": answer, "model": "gpt-4o-mini", "confidence": conf}
    # Tier 2 — powerful model
    answer, conf = sample_answer(question, "gpt-4o", n=1)
    return {"answer": answer, "model": "gpt-4o", "confidence": conf}

print(cascade("What is 2+2?"))          # gpt-4o-mini
print(cascade("Prove Fermat's Last Theorem."))  # escalates to gpt-4o
